#include <stdio.h>
#include <stdbool.h>

bool canAssign(int* intensities, int N, int K, int* sums) {
    if (N == 0) {
        for (int i = 0; i < K; i++) {
            if (sums[i] != sums[0]) return false;
        }
        return true;
    }
    for (int i = 0; i < K; i++) {
        sums[i] += intensities[N - 1];
        if (canAssign(intensities, N - 1, K, sums)) return true;
        sums[i] -= intensities[N - 1];
    }
    return false;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        int intensities[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &intensities[i]);
        }
        int sums[K];
        for (int i = 0; i < K; i++) {
            sums[i] = 0;
        }
        if (canAssign(intensities, N, K, sums)) printf("yes\n");
        else printf("no\n");
    }
    return 0;
}

